import{_ as s,y as d,a as i,o as l,a2 as t,D as r,g as o,I as n}from"./chunks/framework.DCcmcJcL.js";const f=JSON.parse('{"title":"Product Barcode","description":"","frontmatter":{},"headers":[],"relativePath":"multi-vendor-marketplace/product-barcode.md","filePath":"multi-vendor-marketplace/product-barcode.md","lastUpdated":1782735915000}'),c={name:"multi-vendor-marketplace/product-barcode.md"};function p(u,e,h,g,m,b){const a=d("ImagePopup");return l(),i("div",null,[e[0]||(e[0]=t('<h1 id="product-barcode" tabindex="-1">Product Barcode <a class="header-anchor" href="#product-barcode" aria-label="Permalink to &quot;Product Barcode&quot;">​</a></h1><p>The Product Barcode feature lets admins and sellers generate, view, print, and download scannable barcodes for products. Barcodes make in-store lookup, inventory checks, and order packing faster, and they can optionally be shown to customers on the product page.</p><p>Four symbologies are supported:</p><ul><li><strong>Code 128</strong></li><li><strong>EAN-13</strong></li><li><strong>UPC-A</strong></li><li><strong>QR Code</strong> (can encode the product SKU, name, and URL for quick scanning)</li></ul><p>The feature is fully opt-in — existing products are unaffected until a barcode is generated for them.</p><h3 id="admin-configuration" tabindex="-1">Admin Configuration <a class="header-anchor" href="#admin-configuration" aria-label="Permalink to &quot;Admin Configuration&quot;">​</a></h3><p>The admin sets the global barcode behaviour from <strong>Settings → Configuration → Marketplace → Settings → Barcode</strong>.</p><ul><li><p><strong>Default Type:</strong> The symbology used when barcodes are auto-generated (Code 128, EAN-13, UPC-A, or QR Code).</p></li><li><p><strong>Show on Shop:</strong> When enabled, the barcode image is rendered on the storefront product page (after the short description).</p></li></ul>',8)),r(a,{src:"/images/multi-vendor-marketplace/barcode-configuration.png",alt:"Barcode Configuration"}),e[1]||(e[1]=t('<h3 id="barcode-product-attributes" tabindex="-1">Barcode Product Attributes <a class="header-anchor" href="#barcode-product-attributes" aria-label="Permalink to &quot;Barcode Product Attributes&quot;">​</a></h3><p>Three product attributes power the feature and are grouped under a <strong>Barcode</strong> group in every attribute family:</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>barcode_type</code></td><td>Select</td><td>Symbology: Code 128, EAN-13, UPC-A, or QR Code</td></tr><tr><td><code>barcode_value</code></td><td>Text</td><td>The scannable value (e.g. product code, or URL for QR)</td></tr><tr><td><code>barcode_image</code></td><td>Image</td><td>The generated barcode image (created automatically)</td></tr></tbody></table><p>A product receives a barcode image once its <code>barcode_type</code> and <code>barcode_value</code> are set, or automatically when the auto-generation runs on product save.</p><h3 id="auto-generation" tabindex="-1">Auto-Generation <a class="header-anchor" href="#auto-generation" aria-label="Permalink to &quot;Auto-Generation&quot;">​</a></h3><p>Barcodes are generated automatically:</p><ul><li>When a product is <strong>created</strong>.</li><li>When a product is <strong>updated</strong> (the image refreshes).</li><li>Generated files are <strong>cleaned up</strong> when the product is deleted.</li></ul><p>Auto-generation respects the admin&#39;s <strong>Default Type</strong>. To skip a product, leave <code>barcode_type</code> and <code>barcode_value</code> empty — no image is produced.</p><h3 id="admin-—-product-barcode" tabindex="-1">Admin — Product Barcode <a class="header-anchor" href="#admin-—-product-barcode" aria-label="Permalink to &quot;Admin — Product Barcode&quot;">​</a></h3><p>A <strong>Product Barcode</strong> entry is available under the admin <strong>Catalog</strong> menu. From this DataGrid the admin can:</p><ul><li>Browse all products and their barcodes.</li><li><strong>Mass-generate</strong> barcodes for selected products.</li><li><strong>Print</strong> barcodes.</li><li><strong>Download</strong> barcodes as a PDF.</li></ul><p>Access is controlled by three admin permissions: <strong>Product Barcode</strong> (view), <strong>Generate</strong>, and <strong>Download</strong>.</p>',12)),r(a,{src:"/images/multi-vendor-marketplace/admin-product-barcode.png",alt:"Admin Product Barcode DataGrid"}),e[2]||(e[2]=t('<h3 id="seller-—-product-barcode" tabindex="-1">Seller — Product Barcode <a class="header-anchor" href="#seller-—-product-barcode" aria-label="Permalink to &quot;Seller — Product Barcode&quot;">​</a></h3><p>Sellers get a <strong>Product Barcode</strong> entry under <strong>Product Catalog</strong> in the seller panel. From their DataGrid, sellers can browse, mass-generate, print, and download barcodes for <strong>their own</strong> products.</p><p>Access is controlled by three seller permissions: <strong>Product Barcode</strong> (view), <strong>Generate</strong>, and <strong>Download</strong>.</p>',3)),r(a,{src:"/images/multi-vendor-marketplace/seller-product-barcode.png",alt:"Seller Product Barcode DataGrid"}),e[3]||(e[3]=o("h3",{id:"storefront-display",tabindex:"-1"},[n("Storefront Display "),o("a",{class:"header-anchor",href:"#storefront-display","aria-label":'Permalink to "Storefront Display"'},"​")],-1)),e[4]||(e[4]=o("p",null,[n("When "),o("strong",null,"Show on Shop"),n(" is enabled in the admin configuration, the product's barcode image is displayed on the storefront product detail page, just after the short description, so customers can scan it directly.")],-1)),r(a,{src:"/images/multi-vendor-marketplace/barcode-storefront.png",alt:"Barcode on Storefront Product Page"}),e[5]||(e[5]=t(`<h3 id="bulk-generation-command" tabindex="-1">Bulk Generation Command <a class="header-anchor" href="#bulk-generation-command" aria-label="Permalink to &quot;Bulk Generation Command&quot;">​</a></h3><p>Admins can also generate barcodes in bulk from the command line:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace:barcodes:generate</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # generate for products missing a barcode</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace:barcodes:generate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # regenerate for every product</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace:barcodes:generate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type=qr</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # force a specific symbology</span></span></code></pre></div><p>The command processes all products, including configurable variants, with a progress bar.</p>`,4))])}const _=s(c,[["render",p]]);export{f as __pageData,_ as default};
